  function flattenSections(sections){return (sections||[]).flatMap(section=>(section.questions||[]).map(q=>({...q})));}
  function lessonQuestions(lesson){const entry=lesson&&DATA.lessons[lesson.id];return entry?flattenSections(entry.sections):[];}
  function bossQuestions(module){const entry=module&&DATA.unitChallenges[module.id];return entry?entry.questions.map(q=>({...q})):[];}
  function sectionConfig(type){return DATA.sectionConfig[type]||{title:type,instruction:'Complete the activity.',icon:'•'};}
  window.ConnectPlusQuestionsV6WordCorrection={version:DATA.version,sectionOrder:DATA.sectionOrder,sectionConfig,lessonQuestions,bossQuestions,data:DATA};
